   392	// Helper predicates
   393	bool IsDefinition(uint8_t semantic_type) {
   394		return (semantic_type & 0xF0) == DEFINITION;
   395	}
   396	
   397	bool IsCall(uint8_t semantic_type) {
   398		uint8_t base_type = semantic_type & 0xFC; // Mask refinement bits
   399		return base_type == COMPUTATION_CALL || base_type == EXECUTION_STATEMENT_CALL;
   400	}
   401	
   402	bool IsControlFlow(uint8_t semantic_type) {
   403		return (semantic_type & 0xF0) == FLOW_CONTROL;
   404	}
   405	
   406	bool IsIdentifier(uint8_t semantic_type) {
   407		uint8_t base_type = semantic_type & 0xFC; // Mask refinement bits
   408		return base_type == NAME_IDENTIFIER || base_type == NAME_QUALIFIED || base_type == NAME_SCOPED;
   409	}
   410	
   411	bool IsLiteral(uint8_t semantic_type) {
   412		return (semantic_type & 0xF0) == LITERAL;
   413	}
   414	
   415	bool IsOperator(uint8_t semantic_type) {
   416		return (semantic_type & 0xF0) == OPERATOR;
   417	}
   418	
   419	bool IsType(uint8_t semantic_type) {
   420		return (semantic_type & 0xF0) == TYPE;
   421	}
   422	
   423	bool IsExternal(uint8_t semantic_type) {
   424		return (semantic_type & 0xF0) == EXTERNAL;
   425	}
   426	
   427	bool IsError(uint8_t semantic_type) {
   428		return (semantic_type & 0xF0) == ERROR_HANDLING;
   429	}
   430	
   431	bool IsMetadata(uint8_t semantic_type) {
   432		return (semantic_type & 0xF0) == METADATA;
   433	}
   434	
   435	bool IsParserSpecific(uint8_t semantic_type) {
   436		return (semantic_type & 0xF0) == PARSER_SPECIFIC;
   437	}
   438	
   439	bool IsPunctuation(uint8_t semantic_type) {
   440		uint8_t base_type = semantic_type & 0xFC; // Mask refinement bits
   441		return base_type == PARSER_DELIMITER || base_type == PARSER_PUNCTUATION;
   442	}
   443	
   444	// Get all types in a category
   445	vector<uint8_t> GetDefinitionTypes() {
   446		return {DEFINITION_FUNCTION, DEFINITION_VARIABLE, DEFINITION_CLASS, DEFINITION_MODULE};
   447	}
   448	
   449	vector<uint8_t> GetControlFlowTypes() {
   450		return {FLOW_CONDITIONAL, FLOW_LOOP, FLOW_JUMP, FLOW_SYNC};
   451	}
   452	
   453	vector<uint8_t> GetSearchableTypes() {
   454		// Primary search targets - definitions, calls, imports/exports, and control flow
   455		return {// All definitions
   456		        DEFINITION_FUNCTION, DEFINITION_VARIABLE, DEFINITION_CLASS, DEFINITION_MODULE,
   457		        // Calls and access
   458		        COMPUTATION_CALL, COMPUTATION_ACCESS,
   459		        // External dependencies
   460		        EXTERNAL_IMPORT, EXTERNAL_EXPORT,
   461		        // Control flow
   462		        FLOW_CONDITIONAL, FLOW_LOOP, FLOW_JUMP,
   463		        // Error handling
   464		        ERROR_TRY, ERROR_CATCH, ERROR_THROW,
   465		        // Key identifiers
   466		        NAME_IDENTIFIER, NAME_QUALIFIED};
   467	}
   468	
   469	} // namespace SemanticTypes
   470	
   471	} // namespace duckdb
"}

